function solve(nums) {
    const n = nums.length;
    let maxSum = -Infinity;

    // Precompute prefix sums for quick range sum calculation
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefix[i + 1] = prefix[i] + nums[i];
    }

    // Precompute left increasing and right increasing arrays
    const leftInc = new Array(n).fill(0);
    const rightInc = new Array(n).fill(0);

    // Compute leftInc: leftInc[i] is the largest l <= i such that nums[l..i] is strictly increasing
    leftInc[0] = 0;
    for (let i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            leftInc[i] = leftInc[i - 1];
        } else {
            leftInc[i] = i;
        }
    }

    // Compute rightInc: rightInc[i] is the smallest r >= i such that nums[i..r] is strictly increasing
    rightInc[n - 1] = n - 1;
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] < nums[i + 1]) {
            rightInc[i] = rightInc[i + 1];
        } else {
            rightInc[i] = i;
        }
    }

    // Iterate all possible p and q
    for (let p = 1; p < n - 2; p++) {
        for (let q = p + 1; q < n - 1; q++) {
            // Check if nums[p..q] is strictly decreasing
            let valid = true;
            for (let i = p; i < q; i++) {
                if (nums[i] <= nums[i + 1]) {
                    valid = false;
                    break;
                }
            }
            if (!valid) continue;

            // Find l and r
            const l = leftInc[p - 1];
            const r = rightInc[q + 1];

            // Ensure l < p < q < r
            if (l < p && p < q && q < r) {
                const sum = prefix[r + 1] - prefix[l];
                if (sum > maxSum) {
                    maxSum = sum;
                }
            }
        }
    }

    return maxSum;
}

